function filteredProjects() {
  if (state.filter === 'all') return SJ_DATA.projects;
  return SJ_DATA.projects.filter(project => project.category === state.filter);
}

function renderProjects() {
  const all = filteredProjects();
  const perPage = 12;
  const pageCount = Math.max(1, Math.ceil(all.length / perPage));
  state.page = Math.min(state.page, pageCount);
  const pageItems = all.slice((state.page - 1) * perPage, state.page * perPage);
  app.innerHTML = `
    <section class="section project-index">
      <div class="project-filter-band">
        <div class="project-filters reveal">
          <a class="filter-btn ${state.filter === 'all' ? 'is-active' : ''}" href="#/projects/all/1">全部</a><a class="filter-btn ${state.filter === 'offline' ? 'is-active' : ''}" href="#/projects/offline/1">线下</a><a class="filter-btn ${state.filter === 'online' ? 'is-active' : ''}" href="#/projects/online/1">线上</a>
        </div>
      </div>
      <div class="projects-grid">
        ${pageItems.map(project => projectCard(project)).join('')}
      </div>
      <div class="pagination reveal">
        ${Array.from({length: pageCount}, (_, i) => `<a class="page-btn ${state.page === i + 1 ? 'is-active' : ''}" href="${projectsHref(state.filter, i + 1)}">${i + 1}</a>`).join('')}
        ${state.page < pageCount ? `<a class="page-btn next-page" href="${projectsHref(state.filter, state.page + 1)}" aria-label="Next page">›</a>` : ''}
      </div>
    </section>
    ${footer()}`;
  bindProjects();
  bindFooter();
  clearAppClickGuard();
  revealOnScroll();
}

function projectCard(project) {
  const thumb = PROJECT_THUMBS[project.slug] || project.cover;
  return `
    <a class="project-card reveal" href="${projectHref(project)}" data-project-card data-return-hash="${projectsHref(state.filter, state.page)}">
      <div class="project-thumb"><img src="${thumb}" alt="${project.title}" loading="lazy" decoding="async"></div>
      <strong class="project-title">${project.title}</strong>
    </a>`;
}

function renderProjectDetail(slug, returnFilter = state.filter, returnPage = state.page) {
  const project = SJ_DATA.projects.find(item => item.slug === slug);
  if (!project) {
    renderProjects();
    return;
  }
  const backFilter = ['all', 'offline', 'online'].includes(returnFilter) ? returnFilter : 'all';
  const backPage = normalizedProjectPage(returnPage);
  state.filter = backFilter;
  state.page = backPage;
  const backHash = projectsHref(backFilter, backPage);
  rememberProjectReturnHash(backHash);
  app.innerHTML = `
    <article class="project-detail">
      <div class="detail-filter-band">
        <div class="project-filters">
          <button class="filter-btn" type="button" data-filter-link="all">全部</button>
          <button class="filter-btn" type="button" data-filter-link="offline">线下</button>
          <button class="filter-btn" type="button" data-filter-link="online">线上</button>
        </div>
      </div>
      <section class="detail-hero reveal">
        <img class="detail-cover" src="${project.cover}" alt="${project.title}" fetchpriority="high" loading="eager" decoding="async">
      </section>
      <div class="detail-body">
        <aside class="detail-title"><h1>${project.title}</h1></aside>
        <section class="detail-images">
          ${project.images.map((src, index) => `<img class="reveal" src="${src}" alt="${project.title} detail ${index + 1}" loading="lazy" decoding="async">`).join('')}
        </section>
      </div>
      <nav class="detail-nav reveal" aria-label="Project navigation">
        <a href="${backHash}">← BACK TO PROJECTS</a>
        <a href="#/home">HOME</a>
      </nav>
    </article>
    ${footer()}`;
  bindFooter();
  bindProjects();
  bindDetailClickGuard();
  revealOnScroll();
}

