function bindStaticPageGuard() {
  app.onclick = event => {
    if (event.target.closest('a,button,input,textarea,select,label')) return;
    if (!['about', 'contact'].includes(document.body.dataset.page)) return;
    event.preventDefault();
    event.stopPropagation();
  };
}

function clearAppClickGuard() {
  app.onclick = null;
}

function bindHomeClickGuard() {
  app.onclick = event => {
    if (document.body.dataset.page !== 'home') return;
    if (event.target.closest('.carousel-controls,[data-back-top],.footer-nav a')) return;
    event.preventDefault();
    event.stopPropagation();
    if (typeof event.stopImmediatePropagation === 'function') event.stopImmediatePropagation();
  };
}

function bindDetailClickGuard() {
  app.onclick = event => {
    if (document.body.dataset.page !== 'project') return;
    if (event.target.closest('a,button,input,textarea,select,label')) return;
    event.preventDefault();
    event.stopPropagation();
    if (typeof event.stopImmediatePropagation === 'function') event.stopImmediatePropagation();
  };
}

function bindCarousel() {
  clearInterval(state.timer);
  const interval = 6000;
  const ensureSlideImage = index => {
    const img = document.querySelector(`.hero-slide[data-slide="${index}"] img`);
    if (img?.dataset.src && !img.src) {
      img.src = img.dataset.src;
      delete img.dataset.src;
    }
  };
  const update = next => {
    const slides = [...document.querySelectorAll('.hero-slide')];
    if (!slides.length) return;
    state.slide = (next + slides.length) % slides.length;
    ensureSlideImage(state.slide);
    slides.forEach((slide, index) => slide.classList.toggle('is-active', index === state.slide));
    const caption = document.querySelector('[data-caption-title]');
    if (caption) {
      caption.classList.add('is-changing');
      window.setTimeout(() => {
        caption.textContent = HOME_BANNERS[state.slide]?.title || '';
        caption.classList.remove('is-changing');
      }, 180);
    }
  };
  const startTimer = () => {
    clearInterval(state.timer);
    state.timer = setInterval(() => update(state.slide + 1), interval);
  };
  const bindArrow = (selector, direction) => {
    document.querySelector(selector)?.addEventListener('click', event => {
      event.preventDefault();
      event.stopPropagation();
      if (typeof event.stopImmediatePropagation === 'function') event.stopImmediatePropagation();
      update(state.slide + direction);
      startTimer();
    });
  };
  bindArrow('[data-slide-prev]', -1);
  bindArrow('[data-slide-next]', 1);
  const carousel = document.querySelector('.hero-carousel');
  if (carousel) {
    let swipeStartX = 0;
    let swipeStartY = 0;
    let swipeTracking = false;
    let swipeMoved = false;
    let suppressSwipeClick = false;
    const resetSwipe = () => {
      swipeTracking = false;
      swipeMoved = false;
    };

    carousel.addEventListener('pointerdown', event => {
      if (event.pointerType === 'mouse') return;
      swipeStartX = event.clientX;
      swipeStartY = event.clientY;
      swipeTracking = true;
      swipeMoved = false;
    });

    carousel.addEventListener('pointermove', event => {
      if (!swipeTracking) return;
      const dx = event.clientX - swipeStartX;
      const dy = event.clientY - swipeStartY;
      if (Math.abs(dx) > 12 && Math.abs(dx) > Math.abs(dy) * 1.2) {
        swipeMoved = true;
        event.preventDefault();
      }
    });

    carousel.addEventListener('pointerup', event => {
      if (!swipeTracking) return;
      const dx = event.clientX - swipeStartX;
      const dy = event.clientY - swipeStartY;
      const isSwipe = Math.abs(dx) >= 44 && Math.abs(dx) > Math.abs(dy) * 1.15;
      resetSwipe();
      if (!isSwipe) return;
      event.preventDefault();
      event.stopPropagation();
      suppressSwipeClick = true;
      update(state.slide + (dx < 0 ? 1 : -1));
      startTimer();
    });

    carousel.addEventListener('pointercancel', resetSwipe);
    carousel.addEventListener('click', event => {
      if (!suppressSwipeClick) return;
      suppressSwipeClick = false;
      event.preventDefault();
      event.stopPropagation();
    });
  }
  if ('requestIdleCallback' in window) {
    requestIdleCallback(() => ensureSlideImage((state.slide + 1) % HOME_BANNERS.length), { timeout: 2500 });
  } else {
    window.setTimeout(() => ensureSlideImage((state.slide + 1) % HOME_BANNERS.length), 1800);
  }
  startTimer();
}

function bindProjects() {
  document.querySelectorAll('[data-project-card]').forEach(link => {
    link.addEventListener('click', () => {
      const returnHash = link.dataset.returnHash || projectsHref(state.filter, state.page);
      rememberProjectReturnHash(returnHash);
      saveScrollForRoute(returnHash);
    });
  });
  document.querySelectorAll('[data-filter]').forEach(btn => {
    btn.addEventListener('click', () => {
      state.filter = btn.dataset.filter || 'all';
      state.page = 1;
      setRoute(projectsHref(state.filter, 1));
    });
  });
  document.querySelectorAll('[data-filter-link]').forEach(btn => {
    btn.addEventListener('click', () => {
      state.filter = btn.dataset.filterLink || 'all';
      state.page = 1;
      setRoute(projectsHref(state.filter, 1));
    });
  });
  document.querySelectorAll('[data-page]').forEach(btn => {
    btn.addEventListener('click', () => {
      state.page = Number(btn.dataset.page);
      setRoute(projectsHref(state.filter, state.page));
    });
  });
}

function bindFooter() {
  document.querySelectorAll('[data-back-top]').forEach(btn => btn.addEventListener('click', event => {
    event.preventDefault();
    event.stopPropagation();
    if (typeof event.stopImmediatePropagation === 'function') event.stopImmediatePropagation();
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }));
}

function bindMobileMenu() {
  const button = document.querySelector('[data-mobile-menu]');
  const panel = document.querySelector('[data-mobile-panel]');
  if (!button || !panel) return;

  const setOpen = open => {
    button.classList.toggle('is-open', open);
    panel.classList.toggle('is-open', open);
    button.setAttribute('aria-expanded', String(open));
  };

  button.addEventListener('click', event => {
    event.stopPropagation();
    setOpen(!button.classList.contains('is-open'));
  });

  panel.querySelectorAll('a').forEach(link => {
    link.addEventListener('click', () => setOpen(false));
  });

  document.addEventListener('click', event => {
    if (!panel.classList.contains('is-open')) return;
    if (panel.contains(event.target) || button.contains(event.target)) return;
    setOpen(false);
  });

  window.addEventListener('hashchange', () => setOpen(false));
}

function bindSearch() {
  const overlay = document.querySelector('[data-search-overlay]');
  const input = document.querySelector('[data-search-input]');
  const results = document.querySelector('[data-search-results]');
  const openBtn = document.querySelector('[data-search-open]');
  const closeBtn = document.querySelector('[data-search-close]');
  if (!overlay || !input || !results || !openBtn || !closeBtn) return;

  const renderResults = query => {
    const keyword = query.trim().toLowerCase();
    const matches = SJ_DATA.projects.filter(project => {
      const haystack = `${project.title} ${project.slug} ${project.category} ${project.year}`.toLowerCase();
      return !keyword || haystack.includes(keyword);
    }).slice(0, 8);
    results.innerHTML = matches.map(project => `
      <a class="search-result" href="${projectHref(project)}">
        <span>${project.title}</span>
        <small>${project.category === 'online' ? '线上' : '线下'}</small>
      </a>`).join('');
  };

  const setOpen = open => {
    overlay.classList.toggle('is-open', open);
    overlay.setAttribute('aria-hidden', String(!open));
    document.body.classList.toggle('has-search-open', open);
    if (open) {
      renderResults(input.value);
      requestAnimationFrame(() => input.focus());
    }
  };

  openBtn.addEventListener('click', () => setOpen(true));
  closeBtn.addEventListener('click', () => setOpen(false));
  overlay.addEventListener('click', event => {
    if (event.target === overlay) setOpen(false);
  });
  input.addEventListener('input', () => renderResults(input.value));
  results.addEventListener('click', event => {
    if (event.target.closest('a')) setOpen(false);
  });
  window.addEventListener('keydown', event => {
    if (event.key === 'Escape') setOpen(false);
  });
  window.addEventListener('hashchange', () => setOpen(false));
}

function revealOnScroll() {
  const items = [...document.querySelectorAll('.reveal')];
  if (!('IntersectionObserver' in window)) {
    items.forEach(item => item.classList.add('is-visible'));
    return;
  }
  const observer = new IntersectionObserver(entries => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('is-visible');
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.12, rootMargin: '0px 0px -8% 0px' });
  items.forEach(item => observer.observe(item));
}

function capabilitySegments(text, animateByWords) {
  if (animateByWords) {
    return text.split(' ').reduce((segments, word, index, words) => {
      if (!word) return segments;
      segments.push(index < words.length - 1 ? `${word}\u00a0` : word);
      return segments;
    }, []);
  }

  const attachToPrevious = '、，。；：！？）】》';
  return [...text].reduce((segments, char) => {
    const value = char === ' ' ? '\u00a0' : char;
    if (attachToPrevious.includes(char) && segments.length) {
      segments[segments.length - 1] += value;
    } else {
      segments.push(value);
    }
    return segments;
  }, []);
}

function splitCapabilityText(element, baseDelay) {
  if (!element || element.dataset.splitDone === '1') return baseDelay;
  const text = element.textContent.trim();
  const animateByWords = element.classList.contains('capability-en');
  const segmentDelay = animateByWords ? 120 : 34;
  element.textContent = '';
  element.dataset.splitDone = '1';
  let delay = baseDelay;

  capabilitySegments(text, animateByWords).forEach(segment => {
    const span = document.createElement('span');
    span.className = 'blur-segment';
    span.style.animationDelay = `${delay}ms`;
    span.textContent = segment;
    element.appendChild(span);
    delay += segmentDelay;
  });

  return delay + 80;
}

function setupCapabilityMotion() {
  const cards = [...document.querySelectorAll('.home-about .capability')];
  if (!cards.length) return;

  cards.forEach((card, cardIndex) => {
    if (card.dataset.motionReady === '1') return;
    card.dataset.motionReady = '1';
    let delay = cardIndex * 70;
    ['.capability-en', '.capability-no', '.capability-title', '.capability-desc'].forEach(selector => {
      delay = splitCapabilityText(card.querySelector(selector), delay);
    });
  });

  if (!('IntersectionObserver' in window)) {
    cards.forEach(card => card.classList.add('is-motion-in'));
    return;
  }

  const observer = new IntersectionObserver(entries => {
    entries.forEach(entry => {
      if (!entry.isIntersecting) return;
      entry.target.classList.add('is-motion-in');
      observer.unobserve(entry.target);
    });
  }, { threshold: 0.1, rootMargin: '0px' });

  cards.forEach(card => observer.observe(card));
}
function syncScrollState() {
  document.body.classList.toggle('is-scrolled', window.scrollY > 90);
}

function validProjectsHash(hash) {
  return /^#\/projects\/(all|offline|online)\/\d+$/.test(hash || '');
}

function rememberProjectReturnHash(hash) {
  if (!validProjectsHash(hash)) return;
  try {
    sessionStorage.setItem(PROJECT_RETURN_HASH_KEY, hash);
  } catch (error) {}
}

function rememberedProjectReturnHash() {
  try {
    const hash = sessionStorage.getItem(PROJECT_RETURN_HASH_KEY);
    return validProjectsHash(hash) ? hash : '';
  } catch (error) {
    return '';
  }
}

function saveScrollForRoute(hash, y = window.scrollY) {
  if (!hash) return;
  scrollPositions.set(hash, y);
  try {
    sessionStorage.setItem(`${SCROLL_STORAGE_PREFIX}${hash}`, String(y));
  } catch (error) {}
}

function saveCurrentScroll() {
  saveScrollForRoute(activeRouteKey);
}

function storedScrollForRoute(hash) {
  if (scrollPositions.has(hash)) return scrollPositions.get(hash);
  try {
    const value = sessionStorage.getItem(`${SCROLL_STORAGE_PREFIX}${hash}`);
    if (value !== null) return Number(value) || 0;
  } catch (error) {}
  return null;
}

function scrollToRoutePosition(hash, targetSelector) {
  requestAnimationFrame(() => {
    if (targetSelector) {
      const alignTarget = () => {
        const target = document.querySelector(targetSelector);
        if (target) target.scrollIntoView({ block: 'start' });
        syncScrollState();
      };
      alignTarget();
      window.setTimeout(alignTarget, 80);
      window.setTimeout(alignTarget, 360);
      return;
    }

    const storedY = storedScrollForRoute(hash);
    const restore = () => {
      window.scrollTo(0, storedY ?? 0);
      syncScrollState();
    };
    restore();
    if (storedY !== null) {
      window.setTimeout(restore, 80);
      window.setTimeout(restore, 360);
    }
  });
}

function route() {
  clearInterval(state.timer);
  let hash = window.location.hash || '#/home';
  const returningFromProject = activeRouteKey.startsWith('#/project/');
  saveCurrentScroll();
  let parts = hash.replace(/^#\/?/, '').split('/');
  let page = parts[0] || 'home';
  if (returningFromProject && page === 'projects') {
    const returnHash = rememberedProjectReturnHash();
    if (returnHash && returnHash !== hash) {
      history.replaceState(null, '', returnHash);
      hash = returnHash;
      parts = hash.replace(/^#\/?/, '').split('/');
      page = parts[0] || 'home';
    }
  }
  document.body.dataset.page = page;
  let targetSelector = null;
  if (page === 'projects') {
    const filter = parts[1] || 'all';
    state.filter = ['all', 'offline', 'online'].includes(filter) ? filter : 'all';
    state.page = normalizedProjectPage(parts[2]);
    renderProjects();
  }
  else if (page === 'project') renderProjectDetail(decodeURIComponent(parts[1] || ''), parts[2], parts[3]);
  else if (page === 'about') {
    document.body.dataset.page = 'home';
    renderHome();
    targetSelector = '#about';
  }
  else if (page === 'contact') {
    document.body.dataset.page = 'home';
    renderHome();
    targetSelector = '#contact';
  }
  else renderHome();
  activeRouteKey = hash;
  scrollToRoutePosition(hash, targetSelector);
}

function playIntroEntry() {
  if (!document.documentElement.classList.contains('from-intro')) return;
  sessionStorage.removeItem('sjFromIntro');
  requestAnimationFrame(() => {
    document.documentElement.classList.add('is-ready');
  });
}

window.addEventListener('hashchange', route);
window.addEventListener('scroll', syncScrollState, { passive: true });
bindMobileMenu();
bindSearch();
route();
playIntroEntry();





